function useIsMobile() {
  const [mobile, setMobile] = useState(false);
  useEffect(() => {
    const check = () => setMobile(window.innerWidth < 768);
    check();
    window.addEventListener("resize", check);
    return () => window.removeEventListener("resize", check);
  }, []);
  return mobile;
}

function StarRating({ rating, size = 14 }) {
  return (
    <span style={{display:"inline-flex",gap:"2px",alignItems:"center"}}>
      {[0,1,2,3,4].map(i => {
        const fill = Math.min(1, Math.max(0, rating - i));
        const gid = "sr" + i + String(Math.round(rating*10));
        return (
          <svg key={i} width={size} height={size} viewBox="0 0 20 20" style={{display:"inline-block",flexShrink:0}}>
            <defs>
              <linearGradient id={gid}>
                <stop offset={fill*100+"%"} stopColor="#FFD60A"/>
                <stop offset={fill*100+"%"} stopColor="#555" stopOpacity="0.7"/>
              </linearGradient>
            </defs>
            <polygon points="10,1 12.9,7 19.5,7.6 14.5,12 16.2,18.5 10,15 3.8,18.5 5.5,12 0.5,7.6 7.1,7"
              fill={"url(#"+gid+")"} stroke="#FFD60A" strokeWidth="0.4"/>
          </svg>
        );
      })}
    </span>
  );
}

