function ServiceCard({ svc, index }) {
  const [ref,vis] = useReveal(0.08);
  const [hov,setHov] = useState(false);
  const { photo,title,sub,desc } = svc;
  return (
    <div ref={ref} onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}
      style={{borderRadius:"22px",overflow:"hidden",background:"#0d0d0d",
        border:`1px solid ${hov?"rgba(10,132,255,0.5)":"rgba(255,255,255,0.07)"}`,
        transition:`all 0.5s cubic-bezier(.16,1,.3,1) ${index*0.06}s`,
        opacity:vis?1:0,transform:vis?"translateY(0) scale(1)":"translateY(28px) scale(0.97)",
        boxShadow:hov?"0 28px 70px rgba(10,132,255,0.15)":"0 8px 30px rgba(0,0,0,0.5)",cursor:"default"}}>
      <div style={{height:"200px",overflow:"hidden",position:"relative",background:"#0a0a0a"}}>
        <img src={photo} alt={title}
          style={{width:"100%",height:"100%",objectFit:"cover",
            transform:hov?"scale(1.06)":"scale(1)",transition:"transform 0.6s ease",
            filter:"brightness(0.82) saturate(0.9)"}}/>
        <div style={{position:"absolute",inset:0,background:"linear-gradient(to bottom,transparent 40%,rgba(0,0,0,0.55) 100%)"}}/>
        <div style={{position:"absolute",top:"14px",left:"14px",background:"rgba(10,132,255,0.85)",backdropFilter:"blur(8px)",borderRadius:"20px",padding:"4px 13px",fontSize:"10px",fontWeight:800,letterSpacing:"0.08em",textTransform:"uppercase",color:"#fff"}}>{sub}</div>
      </div>
      <div style={{padding:"22px 24px 26px"}}>
        <h3 style={{fontFamily:"'SF Pro Display',-apple-system,sans-serif",fontSize:"18px",fontWeight:700,letterSpacing:"-0.03em",color:"#f5f5f7",margin:"0 0 9px"}}>{title}</h3>
        <p style={{fontSize:"14px",lineHeight:"1.6",color:"rgba(255,255,255,0.48)",margin:0}}>{desc}</p>
      </div>
    </div>
  );
}

function ReviewCarousel({ isMobile }) {
  const [idx,setIdx] = useState(0);
  const [fading,setFading] = useState(false);
  const total = REVIEWS.length;
  const perPage = isMobile ? 1 : 2;
  useEffect(()=>{
    const t = setInterval(()=>advance(1),5500);
    return ()=>clearInterval(t);
  },[idx,isMobile]);
  function advance(dir) {
    setFading(true);
    setTimeout(()=>{setIdx(i=>(i+dir+total)%total);setFading(false);},220);
  }
  const cards = Array.from({length:perPage},(_,i)=>REVIEWS[(idx+i)%total]);
  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:isMobile?"1fr":"repeat(2,1fr)",gap:"16px",transition:"opacity 0.22s ease",opacity:fading?0:1}}>
        {cards.map((r,i)=>(
          <div key={`${idx}-${i}`} style={{background:"rgba(255,255,255,0.03)",border:"1px solid rgba(255,255,255,0.08)",borderRadius:"20px",padding:"24px",backdropFilter:"blur(12px)",display:"flex",flexDirection:"column",gap:"12px"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:"10px"}}>
              <div>
                <div style={{fontWeight:600,fontSize:"15px",color:"#f5f5f7"}}>{r.name}</div>
                <div style={{fontSize:"11px",color:"rgba(255,255,255,0.3)",marginTop:"2px"}}>{r.date}</div>
              </div>
              <ReviewSourceChip src={r.src}/>
            </div>
            <StarRating rating={r.stars} size={13}/>
            <p style={{fontSize:"14px",lineHeight:"1.65",color:"rgba(255,255,255,0.6)",margin:0,fontStyle:"italic"}}>"{r.text}"</p>
          </div>
        ))}
      </div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:"16px",marginTop:"28px"}}>
        <button onClick={()=>advance(-1)} style={{width:"42px",height:"42px",borderRadius:"50%",background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.12)",color:"#f5f5f7",fontSize:"20px",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>‹</button>
        <div style={{display:"flex",gap:"7px",flexWrap:"wrap",justifyContent:"center"}}>
          {REVIEWS.map((_,i)=>(
            <div key={i} onClick={()=>setIdx(i)} style={{width:i===idx?"22px":"7px",height:"7px",borderRadius:"4px",background:i===idx?"#0A84FF":"rgba(255,255,255,0.2)",cursor:"pointer",transition:"all 0.3s ease"}}/>
          ))}
        </div>
        <button onClick={()=>advance(1)} style={{width:"42px",height:"42px",borderRadius:"50%",background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.12)",color:"#f5f5f7",fontSize:"20px",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>›</button>
      </div>
    </div>
  );
}

function Ticker() {
  const doubled = [...TICKER_ITEMS,...TICKER_ITEMS];
  return (
    <div style={{background:"#0A84FF",overflow:"hidden",padding:"13px 0",position:"relative",zIndex:10}}>
      <style>{`
        @keyframes tickerScroll{0%{transform:translateX(0);}100%{transform:translateX(-50%);}}
        .tk{display:flex;width:max-content;animation:tickerScroll 38s linear infinite;}
        .tk:hover{animation-play-state:paused;}
      `}</style>
      <div className="tk">
        {doubled.map((item,i)=>(
          <span key={i} style={{fontSize:"11px",fontWeight:800,color:"#fff",letterSpacing:"0.09em",textTransform:"uppercase",whiteSpace:"nowrap",padding:"0 32px"}}>{item}</span>
        ))}
      </div>
    </div>
  );
}


